@page "/dashboard"
@using sv_75c16d3f3ef346f48eaae81924ec2cfe.Services
@inject WarehouseState WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable
@rendermode InteractiveServer

<PageTitle>Warehouse Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="card">
            <div class="card-body">
                <h5 class="card-title">Current Site</h5>
                <p class="card-text fs-4">@WarehouseState.SelectedWarehouseName</p>
                <p class="text-muted">ID: @WarehouseState.SelectedWarehouseId</p>
            </div>
        </div>
    </div>
    <div class="col-md-6">
        <div class="card">
            <div class="card-body">
                <h5 class="card-title">Low Stock Alerts</h5>
                <p class="card-text fs-1">
                    <AlertBadge />
                </p>
                <p class="text-muted">
                    Items below minimum stock level (refreshes every 10s)
                </p>
            </div>
        </div>
    </div>
</div>

<div class="alert alert-info">
    <strong>How this works:</strong> This page starts polling for low-stock alerts when you
    navigate here and stops when you leave. The alert badge in the sidebar also updates
    because all subscribers share the same scoped <code>InventoryAlertService</code> instance.
    Switch warehouses using the dropdown in the top bar — all components update immediately.
</div>

@code {
    private Action? _warehouseHandler;
    private Action? _alertHandler;

    protected override void OnInitialized()
    {
        _warehouseHandler = () => InvokeAsync(StateHasChanged);
        _alertHandler = () => InvokeAsync(StateHasChanged);

        WarehouseState.OnChange += _warehouseHandler;
        AlertService.OnAlertCountChanged += _alertHandler;

        // Start polling when this page becomes visible
        AlertService.StartPolling();
    }

    public void Dispose()
    {
        // Stop polling when the user leaves this page
        AlertService.StopPolling();
        WarehouseState.OnChange -= _warehouseHandler;
        AlertService.OnAlertCountChanged -= _alertHandler;
    }
}

